import { numberToWords, wordsToNumber } from '../src/numberWords'

let failures = 0
async function check(name: string, got: unknown, want: unknown) {
  got = await got  // resolve promises transparently
  const ok = JSON.stringify(got) === JSON.stringify(want)
  console.log(`  ${ok ? 'PASS' : 'FAIL'} — ${name}`)
  if (!ok) {
    console.log(`       got:  ${JSON.stringify(got)}`)
    console.log(`       want: ${JSON.stringify(want)}`)
    failures++
  }
}

;(async () => {
await check("zero", numberToWords(0), "zero")
await check("one", numberToWords(1), "one")
await check("teens", numberToWords(13), "thirteen")
await check("tens", numberToWords(42), "forty-two")
await check("hundred", numberToWords(100), "one hundred")
await check("142", numberToWords(142), "one hundred forty-two")
await check("thousand", numberToWords(1000), "one thousand")
await check("wordsToNumber forty-two", wordsToNumber("forty-two"), 42)
await check("wordsToNumber hundred", wordsToNumber("one hundred"), 100)
await check("wordsToNumber zero", wordsToNumber("zero"), 0)
console.log(failures === 0 ? 'ALL PASS' : `${failures} FAILURE(S)`)
process.exit(failures === 0 ? 0 : 1)
})()
